class TelegramAPI:
    def __init__(
        self,
        token: str,
        *,
        http_timeout_seconds: int,
        http_max_retries: int,
        http_retry_initial_seconds: float,
        http_retry_max_seconds: float,
        parse_mode: str = "",
    ) -> None:
        self._base_url = f"https://api.telegram.org/bot{token}/"
        self._file_base_url = f"https://api.telegram.org/file/bot{token}/"
        self._http_timeout_seconds = http_timeout_seconds
        self._http_max_retries = max(0, int(http_max_retries))
        self._http_retry_initial_seconds = max(0.0, float(http_retry_initial_seconds))
        self._http_retry_max_seconds = max(0.0, float(http_retry_max_seconds))
        self._parse_mode = (parse_mode or "").strip()
        self._ssl_context = ssl.create_default_context()

    def _request(self, method: str, payload: dict[str, Any] | None) -> Any:
        url = self._base_url + method
        data = None
        # Telegram occasionally closes keep-alive connections without a response; prefer short-lived connections.
        headers = {"Connection": "close"}
        if payload is not None:
            data = urllib.parse.urlencode(payload).encode("utf-8")
            headers["Content-Type"] = "application/x-www-form-urlencoded"

        req = urllib.request.Request(url, data=data, headers=headers, method="POST")
        last_err: Exception | None = None

        for attempt in range(self._http_max_retries + 1):
            try:
                # Use the same SSL context as multipart uploads for consistency.
                with urllib.request.urlopen(req, timeout=self._http_timeout_seconds, context=self._ssl_context) as resp:
                    raw = resp.read().decode("utf-8", errors="replace")
            except urllib.error.HTTPError as e:
                body = e.read().decode("utf-8", errors="replace")
                retry_after = _extract_retry_after_seconds(body)
                if e.code in (429, 500, 502, 503, 504) and attempt < self._http_max_retries:
                    _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, retry_after)
                    continue
                raise RuntimeError(f"Telegram HTTP error calling {method}: {e.code} {body}") from e
            except urllib.error.URLError as e:
                last_err = e
                if attempt < self._http_max_retries:
                    _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, None)
                    continue
                raise RuntimeError(f"Telegram URL error calling {method}: {e}") from e
            except Exception as e:
                # e.g. http.client.RemoteDisconnected, ConnectionResetError, SSL errors, etc.
                last_err = e
                if attempt < self._http_max_retries:
                    _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, None)
                    continue
                raise RuntimeError(f"Telegram request error calling {method}: {e}") from e

            try:
                parsed = json.loads(raw)
            except json.JSONDecodeError as e:
                last_err = e
                if attempt < self._http_max_retries:
                    _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, None)
                    continue
                raise RuntimeError(f"Telegram returned non-JSON for {method}: {raw[:2000]}") from e

            if not parsed.get("ok", False):
                retry_after = None
                try:
                    params = parsed.get("parameters") or {}
                    if isinstance(params, dict) and isinstance(params.get("retry_after"), (int, float)):
                        retry_after = float(params["retry_after"])
                except Exception:
                    retry_after = None
                err_code = parsed.get("error_code")
                if err_code in (429, 500, 502, 503, 504) and attempt < self._http_max_retries:
                    _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, retry_after)
                    continue
                raise RuntimeError(f"Telegram API error calling {method}: {raw[:2000]}")

            return parsed["result"]

        raise RuntimeError(f"Telegram request failed calling {method}: {last_err}")

    def get_updates(self, *, offset: int, timeout_seconds: int) -> list[dict[str, Any]]:
        return self._request(
            "getUpdates",
            {
                "timeout": str(timeout_seconds),
                "offset": str(offset),
                "allowed_updates": json.dumps(["message"]),
            },
        )

    def get_file(self, file_id: str) -> dict[str, Any]:
        """
        Telegram getFile -> returns a dict including file_path, file_size, etc.
        """
        return self._request("getFile", {"file_id": file_id})

    def download_file_to(self, *, file_path: str, dest: Path, max_bytes: int = 0) -> None:
        """
        Download a Telegram file (from getFile.file_path) to dest.
        If max_bytes > 0, abort if download exceeds that size.
        """
        fp = (file_path or "").lstrip("/")
        if not fp:
            raise RuntimeError("Empty Telegram file_path")
        url = self._file_base_url + fp
        req = urllib.request.Request(url, method="GET")
        with urllib.request.urlopen(req, timeout=self._http_timeout_seconds, context=self._ssl_context) as resp:
            total = 0
            dest.parent.mkdir(parents=True, exist_ok=True)
            with dest.open("wb") as f:
                while True:
                    chunk = resp.read(1024 * 64)
                    if not chunk:
                        break
                    total += len(chunk)
                    if max_bytes and max_bytes > 0 and total > max_bytes:
                        raise RuntimeError(f"Download too large (>{max_bytes} bytes)")
                    f.write(chunk)

    def send_message(
        self,
        chat_id: int,
        text: str,
        *,
        reply_to_message_id: int | None = None,
        disable_web_page_preview: bool = True,
    ) -> int | None:
        parse_mode = self._parse_mode
        payload_text = text
        if parse_mode.lower() == "html":
            payload_text = _markdownish_to_telegram_html(payload_text)
            parse_mode = "HTML"
            if len(payload_text) > TELEGRAM_MSG_LIMIT:
                # Best-effort fallback: keep it valid and under Telegram's limit.
                payload_text = _html_escape(text)[:TELEGRAM_MSG_LIMIT]
        elif parse_mode.lower() in ("markdown", "markdownv2"):
            # Not recommended unless you implement proper escaping.
            parse_mode = "MarkdownV2" if parse_mode.lower() == "markdownv2" else "Markdown"
            if len(payload_text) > TELEGRAM_MSG_LIMIT:
                payload_text = payload_text[:TELEGRAM_MSG_LIMIT]
        else:
            parse_mode = ""
            if len(payload_text) > TELEGRAM_MSG_LIMIT:
                payload_text = payload_text[:TELEGRAM_MSG_LIMIT]

        payload: dict[str, Any] = {
            "chat_id": str(chat_id),
            "text": payload_text,
            "disable_web_page_preview": "1" if disable_web_page_preview else "0",
        }
        if reply_to_message_id is not None:
            payload["reply_to_message_id"] = str(reply_to_message_id)
        if parse_mode:
            payload["parse_mode"] = parse_mode
        res = self._request("sendMessage", payload)
        try:
            if isinstance(res, dict) and res.get("message_id") is not None:
                return int(res["message_id"])
        except Exception:
            pass
        return None

    def edit_message_text(
        self,
        chat_id: int,
        message_id: int,
        text: str,
        *,
        disable_web_page_preview: bool = True,
    ) -> None:
        """
        Edit a previously-sent bot message. Used to keep "ticket cards" and /watch status to one message (no spam).
        """
        parse_mode = self._parse_mode
        payload_text = text
        if parse_mode.lower() == "html":
            payload_text = _markdownish_to_telegram_html(payload_text)
            parse_mode = "HTML"
            if len(payload_text) > TELEGRAM_MSG_LIMIT:
                payload_text = _html_escape(text)[:TELEGRAM_MSG_LIMIT]
        elif parse_mode.lower() in ("markdown", "markdownv2"):
            parse_mode = "MarkdownV2" if parse_mode.lower() == "markdownv2" else "Markdown"
            if len(payload_text) > TELEGRAM_MSG_LIMIT:
                payload_text = payload_text[:TELEGRAM_MSG_LIMIT]
        else:
            parse_mode = ""
            if len(payload_text) > TELEGRAM_MSG_LIMIT:
                payload_text = payload_text[:TELEGRAM_MSG_LIMIT]

        payload: dict[str, Any] = {
            "chat_id": str(chat_id),
            "message_id": str(int(message_id)),
            "text": payload_text,
            "disable_web_page_preview": "1" if disable_web_page_preview else "0",
        }
        if parse_mode:
            payload["parse_mode"] = parse_mode
        self._request("editMessageText", payload)

    def send_chat_action(self, chat_id: int, action: str = "typing") -> None:
        """
        Ephemeral UX hint (e.g. "typing") without sending a message.
        """
        self._request("sendChatAction", {"chat_id": str(chat_id), "action": str(action)})

    def set_my_commands(self, commands: list[tuple[str, str]], *, scope_type: str = "", language_code: str = "") -> None:
        """
        Configure Telegram slash-command suggestions shown in the client when user types "/".
        """
        payload_cmds: list[dict[str, str]] = []
        for cmd, desc in commands:
            c = (cmd or "").strip().lstrip("/")
            d = (desc or "").strip()
            if not c or not d:
                continue
            payload_cmds.append({"command": c, "description": d[:256]})
        if not payload_cmds:
            return
        payload: dict[str, str] = {"commands": json.dumps(payload_cmds, ensure_ascii=False)}
        scope_type = (scope_type or "").strip()
        if scope_type:
            payload["scope"] = json.dumps({"type": scope_type}, ensure_ascii=False)
        language_code = (language_code or "").strip()
        if language_code:
            payload["language_code"] = language_code
        self._request(
            "setMyCommands",
            payload,
        )

    def set_chat_menu_button_commands(self) -> None:
        """
        Ensure Telegram clients show the slash command menu button.
        """
        self._request(
            "setChatMenuButton",
            {"menu_button": json.dumps({"type": "commands"}, ensure_ascii=False)},
        )

    def _request_multipart(
        self,
        method: str,
        *,
        fields: dict[str, str],
        file_field: str,
        file_path: Path,
        filename: str,
        content_type: str,
    ) -> Any:
        """
        Minimal multipart/form-data uploader using stdlib only.
        Streams the file content to avoid reading the whole file into memory.
        """
        url = self._base_url + method
        u = urllib.parse.urlparse(url)
        if not u.hostname or not u.path:
            raise RuntimeError(f"Bad Telegram URL: {url}")

        boundary = f"----codexbot_{int(time.time()*1000)}_{os.getpid()}"

        def _part_field(name: str, value: str) -> bytes:
            return (
                f"--{boundary}\r\n"
                f'Content-Disposition: form-data; name="{name}"\r\n'
                f"\r\n"
                f"{value}\r\n"
            ).encode("utf-8")

        def _part_file_header() -> bytes:
            return (
                f"--{boundary}\r\n"
                f'Content-Disposition: form-data; name="{file_field}"; filename="{filename}"\r\n'
                f"Content-Type: {content_type}\r\n"
                f"\r\n"
            ).encode("utf-8")

        closing = f"\r\n--{boundary}--\r\n".encode("utf-8")
        header = _part_file_header()
        field_parts = b"".join(_part_field(k, v) for k, v in fields.items())

        try:
            file_size = file_path.stat().st_size
        except OSError as e:
            raise RuntimeError(f"Failed to stat upload file: {file_path} ({e})") from e

        content_length = len(field_parts) + len(header) + file_size + len(closing)

        last_err: Exception | None = None
        for attempt in range(self._http_max_retries + 1):
            conn: http.client.HTTPSConnection | None = None
            try:
                conn = http.client.HTTPSConnection(u.hostname, timeout=self._http_timeout_seconds, context=self._ssl_context)
                conn.putrequest("POST", u.path)
                conn.putheader("Content-Type", f"multipart/form-data; boundary={boundary}")
                conn.putheader("Content-Length", str(content_length))
                conn.endheaders()

                conn.send(field_parts)
                conn.send(header)
                with file_path.open("rb") as f:
                    while True:
                        chunk = f.read(1024 * 64)
                        if not chunk:
                            break
                        conn.send(chunk)
                conn.send(closing)

                resp = conn.getresponse()
                raw_bytes = resp.read()
                raw = raw_bytes.decode("utf-8", errors="replace")

                if resp.status >= 400:
                    retry_after = _extract_retry_after_seconds(raw)
                    if resp.status in (429, 500, 502, 503, 504) and attempt < self._http_max_retries:
                        _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, retry_after)
                        continue
                    raise RuntimeError(f"Telegram HTTP error calling {method}: {resp.status} {raw[:2000]}")

                try:
                    parsed = json.loads(raw)
                except json.JSONDecodeError as e:
                    last_err = e
                    if attempt < self._http_max_retries:
                        _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, None)
                        continue
                    raise RuntimeError(f"Telegram returned non-JSON for {method}: {raw[:2000]}") from e

                if not parsed.get("ok", False):
                    retry_after = None
                    try:
                        params = parsed.get("parameters") or {}
                        if isinstance(params, dict) and isinstance(params.get("retry_after"), (int, float)):
                            retry_after = float(params["retry_after"])
                    except Exception:
                        retry_after = None
                    err_code = parsed.get("error_code")
                    if err_code in (429, 500, 502, 503, 504) and attempt < self._http_max_retries:
                        _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, retry_after)
                        continue
                    raise RuntimeError(f"Telegram API error calling {method}: {raw[:2000]}")

                return parsed["result"]
            except Exception as e:
                last_err = e
                if attempt < self._http_max_retries:
                    _sleep_retry(attempt, self._http_retry_initial_seconds, self._http_retry_max_seconds, None)
                    continue
                raise
            finally:
                try:
                    if conn is not None:
                        conn.close()
                except Exception:
                    pass

        raise RuntimeError(f"Telegram request failed calling {method}: {last_err}")

    def send_document(
        self,
        chat_id: int,
        file_path: Path,
        *,
        filename: str | None = None,
        caption: str | None = None,
        reply_to_message_id: int | None = None,
    ) -> None:
        fields: dict[str, str] = {"chat_id": str(chat_id)}
        if caption:
            fields["caption"] = caption
        if reply_to_message_id is not None:
            fields["reply_to_message_id"] = str(reply_to_message_id)
        fn = filename or file_path.name
        ctype = mimetypes.guess_type(fn)[0] or "application/octet-stream"
        if ctype.startswith("text/"):
            ctype = f"{ctype}; charset=utf-8"
        self._request_multipart(
            "sendDocument",
            fields=fields,
            file_field="document",
            file_path=file_path,
            filename=fn,
            content_type=ctype,
        )

    def send_photo(
        self,
        chat_id: int,
        file_path: Path,
        *,
        filename: str | None = None,
        caption: str | None = None,
        reply_to_message_id: int | None = None,
    ) -> None:
        """
        Send an image with inline preview in Telegram clients.
        """
        fields: dict[str, str] = {"chat_id": str(chat_id)}
        if caption:
            fields["caption"] = caption
        if reply_to_message_id is not None:
            fields["reply_to_message_id"] = str(reply_to_message_id)
        fn = filename or file_path.name
        ctype = mimetypes.guess_type(fn)[0] or "application/octet-stream"
        self._request_multipart(

            "sendPhoto",
            fields=fields,
            file_field="photo",
            file_path=file_path,
            filename=fn,
            content_type=ctype,
        )

    def send_voice(
        self,
        chat_id: int,
        file_path: Path,
        *,
        filename: str | None = None,
        caption: str | None = None,
        reply_to_message_id: int | None = None,
    ) -> int | None:
        """
        Send a Telegram voice note (OGG/Opus).
        """
        fields: dict[str, str] = {"chat_id": str(chat_id)}
        if caption:
            # Telegram captions have a smaller limit than messages; keep it conservative.
            fields["caption"] = caption[:900]
        if reply_to_message_id is not None:
            fields["reply_to_message_id"] = str(reply_to_message_id)
        fn = filename or file_path.name or "voice.ogg"
        res = self._request_multipart(
            "sendVoice",
            fields=fields,
            file_field="voice",
            file_path=file_path,
            filename=fn,
            content_type="audio/ogg",
        )
        try:
            if isinstance(res, dict) and res.get("message_id") is not None:
                return int(res["message_id"])
        except Exception:
            pass
        return None


class OpenAITranscriber:
    """
    Minimal OpenAI speech-to-text client (stdlib-only).
    Uses multipart/form-data to POST to /v1/audio/transcriptions.
    """

    def __init__(
        self,
        *,
        api_key: str,
        api_base_url: str,
        timeout_seconds: int,
        max_retries: int,
        retry_initial_seconds: float,
        retry_max_seconds: float,
    ) -> None:
        self._api_key = (api_key or "").strip()
        self._base = (api_base_url or "https://api.openai.com").strip().rstrip("/")
        self._timeout_seconds = int(timeout_seconds)
        self._max_retries = max(0, int(max_retries))
        self._retry_initial_seconds = max(0.0, float(retry_initial_seconds))
        self._retry_max_seconds = max(0.0, float(retry_max_seconds))
        self._ssl_context = ssl.create_default_context()

    def _post_multipart(
        self,
        *,
        url: str,
        fields: dict[str, str],
        file_field: str,
        file_path: Path,
        filename: str,
        content_type: str,
    ) -> dict[str, Any]:
        u = urllib.parse.urlparse(url)
        if u.scheme != "https" or not u.hostname or not u.path:
            raise RuntimeError(f"Bad OpenAI URL: {url}")

        boundary = f"----codexbot_openai_{int(time.time()*1000)}_{os.getpid()}"

        def _part_field(name: str, value: str) -> bytes:
            return (
                f"--{boundary}\r\n"
                f'Content-Disposition: form-data; name="{name}"\r\n'
                f"\r\n"
                f"{value}\r\n"
            ).encode("utf-8")

        def _part_file_header() -> bytes:
            return (
                f"--{boundary}\r\n"
                f'Content-Disposition: form-data; name="{file_field}"; filename="{filename}"\r\n'
                f"Content-Type: {content_type}\r\n"
                f"\r\n"
            ).encode("utf-8")

        closing = f"\r\n--{boundary}--\r\n".encode("utf-8")
        header = _part_file_header()
        field_parts = b"".join(_part_field(k, v) for k, v in fields.items())

        try:
            file_size = file_path.stat().st_size
        except OSError as e:
            raise RuntimeError(f"Failed to stat audio file: {file_path} ({e})") from e

        content_length = len(field_parts) + len(header) + file_size + len(closing)

        last_err: Exception | None = None
        for attempt in range(self._max_retries + 1):
            conn: http.client.HTTPSConnection | None = None
            try:
                conn = http.client.HTTPSConnection(u.hostname, timeout=self._timeout_seconds, context=self._ssl_context)
                conn.putrequest("POST", u.path)
                conn.putheader("Authorization", f"Bearer {self._api_key}")
                conn.putheader("Content-Type", f"multipart/form-data; boundary={boundary}")
                conn.putheader("Content-Length", str(content_length))
                conn.putheader("Connection", "close")
                conn.endheaders()

                conn.send(field_parts)
                conn.send(header)
                with file_path.open("rb") as f:
                    while True:
                        chunk = f.read(1024 * 64)
                        if not chunk:
                            break
                        conn.send(chunk)
                conn.send(closing)

                resp = conn.getresponse()
                raw_bytes = resp.read()
                raw = raw_bytes.decode("utf-8", errors="replace")
                if resp.status >= 400:
                    if resp.status in (429, 500, 502, 503, 504) and attempt < self._max_retries:
                        _sleep_retry(attempt, self._retry_initial_seconds, self._retry_max_seconds, None)
                        continue
                    raise RuntimeError(f"OpenAI HTTP error: {resp.status} {raw[:2000]}")

                try:
                    parsed = json.loads(raw)
                except Exception as e:
                    raise RuntimeError(f"OpenAI returned non-JSON: {raw[:2000]}") from e
                if not isinstance(parsed, dict):
                    raise RuntimeError("OpenAI returned unexpected JSON")
                return parsed
            except Exception as e:
                last_err = e
                if attempt < self._max_retries:
                    _sleep_retry(attempt, self._retry_initial_seconds, self._retry_max_seconds, None)
                    continue
                raise
            finally:
                try:
                    if conn is not None:
                        conn.close()
                except Exception:
                    pass

        raise RuntimeError(f"OpenAI request failed: {last_err}")

    def transcribe(
        self,
        *,
        audio_path: Path,
        model: str,
        language: str = "",
        prompt: str = "",
    ) -> str:
        if not self._api_key:
            raise RuntimeError("Missing OpenAI API key")
        model = (model or "").strip()
        if not model:
            raise RuntimeError("Missing transcription model")

        fields: dict[str, str] = {
            "model": model,
            "response_format": "json",
        }
        lang = (language or "").strip()
        if lang:
            fields["language"] = lang
        pr = (prompt or "").strip()
        if pr:
            fields["prompt"] = pr

        fn = audio_path.name
        ctype = mimetypes.guess_type(fn)[0] or "application/octet-stream"
        url = self._base + "/v1/audio/transcriptions"
        parsed = self._post_multipart(
            url=url,
            fields=fields,
            file_field="file",
            file_path=audio_path,
            filename=fn,
            content_type=ctype,
        )
        txt = parsed.get("text")
        return txt.strip() if isinstance(txt, str) else ""


class OpenAITTS:
    """
    Minimal OpenAI text-to-speech client (stdlib-only).
    Uses JSON POST to /v1/audio/speech and returns raw audio bytes.
    """

    def __init__(
        self,
        *,
        api_key: str,
        api_base_url: str,
        timeout_seconds: int,
        max_retries: int,
        retry_initial_seconds: float,
        retry_max_seconds: float,
    ) -> None:
        self._api_key = (api_key or "").strip()
        self._base = (api_base_url or "https://api.openai.com").strip().rstrip("/")
        self._timeout_seconds = int(timeout_seconds)
        self._max_retries = max(0, int(max_retries))
        self._retry_initial_seconds = max(0.0, float(retry_initial_seconds))
        self._retry_max_seconds = max(0.0, float(retry_max_seconds))
        self._ssl_context = ssl.create_default_context()

    def synthesize(
        self,
        *,
        text: str,
        model: str,
        voice: str,
        response_format: str,
    ) -> bytes:
        if not self._api_key:
            raise RuntimeError("Missing OpenAI API key")
        t = (text or "").strip()
        if not t:
            raise RuntimeError("Empty TTS input")
        m = (model or "").strip() or "tts-1"
        v = (voice or "").strip() or "alloy"
        fmt = (response_format or "").strip().lower() or "mp3"

        url = self._base + "/v1/audio/speech"
        u = urllib.parse.urlparse(url)
        if u.scheme != "https" or not u.hostname or not u.path:
            raise RuntimeError(f"Bad OpenAI URL: {url}")

        body = json.dumps(
            {
                "model": m,
                "input": t,
                "voice": v,
                "response_format": fmt,
            },
            ensure_ascii=False,
        ).encode("utf-8")

        last_err: Exception | None = None
        for attempt in range(self._max_retries + 1):
            conn: http.client.HTTPSConnection | None = None
            try:
                conn = http.client.HTTPSConnection(u.hostname, timeout=self._timeout_seconds, context=self._ssl_context)
                conn.putrequest("POST", u.path)
                conn.putheader("Authorization", f"Bearer {self._api_key}")
                conn.putheader("Content-Type", "application/json; charset=utf-8")
                conn.putheader("Content-Length", str(len(body)))
                conn.putheader("Connection", "close")
                conn.endheaders()
                conn.send(body)

                resp = conn.getresponse()

                raw = resp.read()
                if resp.status >= 400:
                    msg = raw.decode("utf-8", errors="replace")
                    if resp.status in (429, 500, 502, 503, 504) and attempt < self._max_retries:
                        _sleep_retry(attempt, self._retry_initial_seconds, self._retry_max_seconds, None)
                        continue
                    raise RuntimeError(f"OpenAI TTS HTTP error: {resp.status} {msg[:2000]}")
                return raw
            except Exception as e:
                last_err = e
                if attempt < self._max_retries:
                    _sleep_retry(attempt, self._retry_initial_seconds, self._retry_max_seconds, None)
                    continue
                raise
            finally:
                try:
                    if conn is not None:
                        conn.close()
                except Exception:
                    pass

        raise RuntimeError(f"OpenAI TTS request failed: {last_err}")


class WhisperCppTranscriber:
    """
    Local/offline transcriber using whisper.cpp + ffmpeg.
    """

    def __init__(
        self,
        *,
        ffmpeg_bin: str,
        whisper_bin: str,
        model_path: str,
        threads: int,
        timeout_seconds: int,
        language: str,
        prompt: str,
    ) -> None:
        self._ffmpeg = (ffmpeg_bin or "").strip()
        self._whisper = (whisper_bin or "").strip()
        self._model_path = (model_path or "").strip()
        self._threads = int(threads) if int(threads) > 0 else 1
        self._timeout_seconds = int(timeout_seconds) if int(timeout_seconds) > 0 else 300
        self._language = (language or "").strip()
        self._prompt = (prompt or "").strip()

    @staticmethod
    def _is_exec_available(cmd: str) -> bool:
        if not cmd:
            return False
        if Path(cmd).expanduser().exists():
            return True
        return shutil.which(cmd) is not None

    def is_available(self) -> tuple[bool, str]:
        if not self._is_exec_available(self._ffmpeg):
            return False, f"ffmpeg no encontrado: {self._ffmpeg or '(empty)'}"
        if not self._is_exec_available(self._whisper):
            return False, f"whisper.cpp bin no encontrado: {self._whisper or '(empty)'}"
        if not self._model_path or not Path(self._model_path).expanduser().exists():
            return False, f"modelo whisper.cpp no encontrado: {self._model_path or '(empty)'}"
        return True, ""

    def _run(self, argv: list[str]) -> subprocess.CompletedProcess[str]:
        return subprocess.run(
            argv,
            capture_output=True,
            text=True,
            timeout=self._timeout_seconds,
        )

    def transcribe_file(self, *, input_path: Path) -> str:
        ok, reason = self.is_available()
        if not ok:
            raise RuntimeError(reason)

        input_path = input_path.expanduser().resolve()
        if not input_path.exists():
            raise RuntimeError(f"audio no existe: {input_path}")

        tmp_dir = Path(tempfile.mkdtemp(prefix="codexbot_whisper_", dir=str(input_path.parent)))
        wav_path = tmp_dir / "audio.wav"
        out_prefix = tmp_dir / "out"
        out_txt = Path(str(out_prefix) + ".txt")

        try:
            ffmpeg = str(Path(self._ffmpeg).expanduser()) if Path(self._ffmpeg).expanduser().exists() else self._ffmpeg
            whisper = str(Path(self._whisper).expanduser()) if Path(self._whisper).expanduser().exists() else self._whisper
            model = str(Path(self._model_path).expanduser())

            # Convert to 16kHz mono WAV (whisper.cpp expects PCM WAV).
            p1 = self._run(
                [
                    ffmpeg,
                    "-y",
                    "-i",
                    str(input_path),
                    "-ac",
                    "1",
                    "-ar",
                    "16000",
                    "-f",
                    "wav",
                    str(wav_path),
                ]
            )
            if p1.returncode != 0 or not wav_path.exists():
                raise RuntimeError(f"ffmpeg fallo: {(p1.stderr or p1.stdout or '').strip()[:2000]}")

            # whisper.cpp: write plain text output to out_prefix.txt
            cmd = [
                whisper,
                "-m",
                model,
                "-f",
                str(wav_path),
                "-otxt",
                "-of",
                str(out_prefix),
                "-nt",  # no timestamps
                "-t",
                str(self._threads),
            ]
            if self._language:
                cmd += ["-l", self._language]
            if self._prompt:
                cmd += ["--prompt", self._prompt]

            p2 = self._run(cmd)
            if p2.returncode != 0:
                raise RuntimeError(f"whisper.cpp fallo: {(p2.stderr or p2.stdout or '').strip()[:2000]}")
            try:
                txt = out_txt.read_text(encoding="utf-8", errors="replace").strip()
            except Exception as e:
                raise RuntimeError(f"no pude leer transcripcion: {e}") from e
            return txt
        finally:
            try:
                for p in tmp_dir.glob("*"):
                    p.unlink(missing_ok=True)
                tmp_dir.rmdir()
            except Exception:
                pass


def _state_store_for_path(path: Path) -> StateStore:
    key = str(Path(path).expanduser().resolve())
    with _STATE_STORES_LOCK:
        store = _STATE_STORES_BY_PATH.get(key)
        if store is None:
            store = StateStore(Path(key))
            _STATE_STORES_BY_PATH[key] = store
        return store


def _state_store(cfg: "BotConfig") -> StateStore:
    return _state_store_for_path(cfg.state_file)


def _atomic_write_json(path: Path, data: dict[str, Any]) -> None:
    _state_store_for_path(path).replace(data)


def _read_json(path: Path) -> dict[str, Any]:
    return _state_store_for_path(path).read()


def _update_state(cfg: "BotConfig", mutator: Callable[[dict[str, Any]], None]) -> dict[str, Any]:
    return _state_store(cfg).update(mutator)


def _get_state(cfg: "BotConfig") -> dict[str, Any]:
    return _state_store(cfg).read()


_FACTORY_CEO_STRATEGY_NEXT_ACTION_TYPES = frozenset(
    {
        "ceo_approval_needed",
        "ceo_approval_request",
        "request_ceo_approval",
        "strategic_proposal",
        "strategic_ceo_approval",
    }
)


def _factory_ceo_strategy_timeout_seconds() -> int:
    try:
        raw = int(os.environ.get("BOT_FACTORY_CEO_APPROVAL_TIMEOUT_SECONDS", "1800"))
    except Exception:
        raw = 1800
    return max(300, min(24 * 60 * 60, int(raw)))


def _factory_ceo_strategy_records(cfg: "BotConfig") -> dict[str, dict[str, Any]]:
    state = _get_state(cfg)
    raw = state.get("factory_ceo_strategy_proposals")
    if not isinstance(raw, dict):
        return {}
    out: dict[str, dict[str, Any]] = {}
    for order_id, record in raw.items():
        oid = str(order_id or "").strip()
        if not oid or not isinstance(record, dict):
            continue
        out[oid] = dict(record)
    return out


def _update_factory_ceo_strategy_records(
    cfg: "BotConfig",
    mutator: Callable[[dict[str, dict[str, Any]]], None],
) -> dict[str, dict[str, Any]]:
    updated = _update_state(
        cfg,
        lambda st: _mutate_factory_ceo_strategy_records_in_state(st, mutator),
    )
    raw = updated.get("factory_ceo_strategy_proposals")
    if not isinstance(raw, dict):
        return {}
    return {
        str(order_id): dict(record)
        for order_id, record in raw.items()
        if str(order_id or "").strip() and isinstance(record, dict)
    }


def _mutate_factory_ceo_strategy_records_in_state(
    state: dict[str, Any],
    mutator: Callable[[dict[str, dict[str, Any]]], None],
) -> None:
    raw = state.get("factory_ceo_strategy_proposals")
    records: dict[str, dict[str, Any]] = {}
    if isinstance(raw, dict):
        for order_id, record in raw.items():
            oid = str(order_id or "").strip()
            if oid and isinstance(record, dict):
                records[oid] = dict(record)
    mutator(records)
    state["factory_ceo_strategy_proposals"] = records


def _normalize_text_list(value: Any, *, max_items: int = 8, max_chars: int = 240) -> list[str]:
    if not isinstance(value, list):
        return []
    out: list[str] = []
    for raw in value:
        item = str(raw or "").strip()
        if not item:
            continue
        if len(item) > max_chars:
            item = item[:max_chars].rstrip() + "..."
        out.append(item)
        if len(out) >= max_items:
            break
    return out


def _factory_ceo_strategy_next_action(structured_digest: Any) -> dict[str, Any] | None:
    if not isinstance(structured_digest, dict):
        return None
    raw_next = structured_digest.get("next_action")
    if not isinstance(raw_next, dict):
        return None
    next_type = str(raw_next.get("type") or "").strip().lower()
    if next_type not in _FACTORY_CEO_STRATEGY_NEXT_ACTION_TYPES:
        return None
    return dict(raw_next)


def _extract_factory_ceo_strategy_proposal(
    *,
    structured_digest: Any,
    summary: str,
    order_id: str,
    repo_id: str = "",
    repo_path: str = "",
) -> dict[str, Any] | None:
    next_action = _factory_ceo_strategy_next_action(structured_digest)
    if next_action is None:
        return None
    proposal_title = str(
        next_action.get("proposal_title")
        or next_action.get("title")
        or next_action.get("plan_title")
        or "Strategic proposal awaiting CEO approval"
    ).strip()
    proposal_summary = str(
        next_action.get("proposal_summary")
        or next_action.get("summary")
        or next_action.get("proposal")
        or summary
        or "Skynet proposes a larger strategic change and is waiting for CEO approval."
    ).strip()
    why_now = str(next_action.get("why_now") or next_action.get("why") or "").strip()
    fallback_work = str(
        next_action.get("fallback_work")
        or next_action.get("fallback")
        or "If no reply arrives in time, continue with bounded reliability, maintenance, and delivery work."
    ).strip()
    change_class = str(
        next_action.get("change_class")
        or next_action.get("change_type")
        or next_action.get("scope_class")
        or "strategic_change"
    ).strip()
    return {
        "order_id": str(order_id or "").strip(),
        "repo_id": str(repo_id or "").strip(),
        "repo_path": str(repo_path or "").strip(),
        "proposal_title": proposal_title,
        "proposal_summary": proposal_summary,
        "why_now": why_now,
        "scope": _normalize_text_list(next_action.get("scope") or next_action.get("planned_scope") or []),
        "risks": _normalize_text_list(next_action.get("risks") or next_action.get("tradeoffs") or []),
        "questions": _normalize_text_list(next_action.get("questions") or next_action.get("approvals_needed") or []),
        "assumptions": _normalize_text_list(next_action.get("assumptions") or []),
        "fallback_work": fallback_work,
        "change_class": change_class,
        "next_action_type": str(next_action.get("type") or "").strip().lower(),
    }


def _factory_ceo_strategy_proposal_text(record: dict[str, Any], *, timeout_seconds: int) -> str:
    order_id = str(record.get("order_id") or "").strip()
    repo_id = str(record.get("repo_id") or "").strip()
    repo_path = str(record.get("repo_path") or "").strip()
    proposal_title = str(record.get("proposal_title") or "").strip() or "Strategic proposal"
    proposal_summary = str(record.get("proposal_summary") or "").strip()
    change_class = str(record.get("change_class") or "").strip() or "strategic_change"
    timeout_minutes = max(1, int(round(float(timeout_seconds) / 60.0)))
    lines = [
        "Skynet requests CEO approval for a larger strategic change.",
        f"Order: {order_id[:8] if order_id else 'n/a'}",
        f"Type: {change_class}",
    ]
    if repo_id:
        lines.append(f"Repo: {repo_id}")
    elif repo_path:
        lines.append(f"Repo path: {repo_path}")
    lines.extend(["", f"Proposal: {proposal_title}"])
    if proposal_summary:
        lines.append(proposal_summary)
    why_now = str(record.get("why_now") or "").strip()
    if why_now:
        lines.extend(["", f"Why now: {why_now}"])
    for label, key in (
        ("Scope", "scope"),
        ("Risks", "risks"),
        ("Questions", "questions"),
        ("Assumptions", "assumptions"),
    ):
        values = record.get(key)
        if not isinstance(values, list) or not values:
            continue
        lines.append("")
        lines.append(f"{label}:")
        for item in values[:8]:
            lines.append(f"- {str(item)}")
    fallback_work = str(record.get("fallback_work") or "").strip()
    if fallback_work:
        lines.extend(["", f"If no reply in {timeout_minutes} min: {fallback_work}"])
    lines.extend(
        [
            "",
            "Reply to this message with:",
            "- si / yes / approve",
            "- no / reject",
            "- or plain-text questions/changes and Skynet will replan",
            f"- command alternative: /proposal approve {order_id[:8] if order_id else ''}".rstrip(),
        ]
    )
    return "\n".join(lines).strip()


def _normalize_factory_ceo_strategy_reply_text(text: str) -> str:
    raw = str(text or "").strip().lower()
    return (
        raw.replace("á", "a")
        .replace("é", "e")
        .replace("í", "i")
        .replace("ó", "o")
        .replace("ú", "u")
    )


def _classify_factory_ceo_strategy_reply(text: str) -> str:
    normalized = _normalize_factory_ceo_strategy_reply_text(text)
    if not normalized:
        return "replan"
    if any(
        token in normalized
        for token in (
            " reject",
            "rechaza",
            "rechazar",
            "no apruebo",
            "no aprobar",
            "no procede",
            "cancela",
            "cancelar",
        )
    ) or normalized in ("no", "nop", "nope", "reject", "rechazo"):
        return "reject"
    if any(
        token in normalized
        for token in ("?", "pero", "cambia", "ajusta", "modifica", "instead", "quiero", "pregunta")
    ):
        return "replan"
    if normalized in ("si", "sí", "yes", "approve", "approved", "dale", "ok", "ok dale", "aprobado"):
        return "approve"
    if normalized.startswith(("si ", "yes ", "approve ", "approved ", "aprob", "dale ", "ok ")):
        return "approve"
    return "replan"


def _resolve_factory_ceo_strategy_order_id(
    cfg: "BotConfig",
    *,
    order_id: str,
    chat_id: int | None = None,
) -> str:
    token = str(order_id or "").strip().lower()
    if not token:
        return ""
    records = _factory_ceo_strategy_records(cfg)
    exact = records.get(token)
    if isinstance(exact, dict):
        if chat_id is None or int(exact.get("chat_id") or 0) == int(chat_id):
            return token
    matches = []
    for oid, record in records.items():
        if not oid.startswith(token):
            continue
        if chat_id is not None and int(record.get("chat_id") or 0) != int(chat_id):
            continue
        matches.append(oid)
    return matches[0] if len(matches) == 1 else ""


def _pending_factory_ceo_strategy_proposal_for_order(
    cfg: "BotConfig",
    *,
    order_id: str,
    now: float | None = None,
) -> dict[str, Any] | None:
    oid = _resolve_factory_ceo_strategy_order_id(cfg, order_id=order_id)
    if not oid:
        return None
    record = _factory_ceo_strategy_records(cfg).get(oid)
    if not isinstance(record, dict):
        return None
    if str(record.get("status") or "").strip().lower() != "pending":
        return None
    try:
        expires_at = float(record.get("expires_at") or 0.0)
    except Exception:
        expires_at = 0.0
    now_ts = float(time.time() if now is None else now)
    if expires_at > 0 and now_ts >= expires_at:
        return None
    return dict(record)


def _pending_factory_ceo_strategy_proposal_for_reply(
    cfg: "BotConfig",
    *,
    chat_id: int,
    reply_to_message_id: int,
    now: float | None = None,
) -> dict[str, Any] | None:
    target_chat = int(chat_id)
    target_message = int(reply_to_message_id)
    now_ts = float(time.time() if now is None else now)
    for record in _factory_ceo_strategy_records(cfg).values():
        if str(record.get("status") or "").strip().lower() != "pending":
            continue
        try:
            if int(record.get("chat_id") or 0) != target_chat:
                continue
            if int(record.get("message_id") or 0) != target_message:
                continue
            expires_at = float(record.get("expires_at") or 0.0)
        except Exception:
            continue
        if expires_at > 0 and now_ts >= expires_at:
            continue
        return dict(record)
    return None


def _order_has_pending_factory_ceo_strategy_proposal(
    cfg: "BotConfig",
    *,
    order_id: str,
    now: float | None = None,
) -> bool:
    return _pending_factory_ceo_strategy_proposal_for_order(cfg, order_id=order_id, now=now) is not None


