def _drain_pending_updates(cfg: BotConfig, api: TelegramAPI) -> int:
    """
    Returns the next offset to use.
    This intentionally discards any pending updates so a restart doesn't re-run old commands.
    """
    offset = 0
    drained = 0
    for _ in range(20):
        try:
            updates = api.get_updates(offset=offset, timeout_seconds=0)
        except Exception as exc:
            # On boot, DNS/network can be temporarily unavailable. Draining is a convenience, not a requirement.
            # If we crash here, systemd may hit StartLimit* and leave the bot "off" until manually restarted.
            LOG.warning(
                "Failed to drain pending Telegram updates; continuing without drain: %s",
                exc,
            )
            break
        if not updates:
            break
        for upd in updates:
            update_id = int(upd.get("update_id", -1))
            if update_id >= 0:
                offset = max(offset, update_id + 1)
        drained += len(updates)
    if drained:
        LOG.info("Drained %d pending Telegram updates; next offset=%d", drained, offset)
    return offset


def _normalize_notify_scope(raw: str | None) -> str:
    v = str(raw or "").strip().lower()
    if v in ("critical", "state_change", "digest_only"):
        return v
    return "state_change"


def _effective_notify_scope(cfg: "BotConfig", *, chat_id: int | None = None) -> str:
    st = _get_state(cfg)
    if chat_id is not None:
        by_chat = st.get("notify_scope_by_chat")
        if isinstance(by_chat, dict):
            rec = by_chat.get(str(int(chat_id)))
            if isinstance(rec, str) and rec.strip():
                return _normalize_notify_scope(rec)
    global_scope = st.get("notify_scope")
    if isinstance(global_scope, str) and global_scope.strip():
        return _normalize_notify_scope(global_scope)
    return _normalize_notify_scope(getattr(cfg, "notify_scope", "state_change"))


def _set_notify_scope(cfg: "BotConfig", scope: str, *, chat_id: int | None = None) -> None:
    normalized = _normalize_notify_scope(scope)

    def _m(st: dict[str, Any]) -> None:
        if chat_id is None:
            st["notify_scope"] = normalized
            return
        by_chat = st.get("notify_scope_by_chat")
        if not isinstance(by_chat, dict):
            by_chat = {}
        by_chat[str(int(chat_id))] = normalized
        st["notify_scope_by_chat"] = by_chat

    _update_state(cfg, _m)


def _notification_dedupe_allow(cfg: "BotConfig", *, key: str, cooldown_seconds: int) -> bool:
    k = str(key or "").strip()
    if not k:
        return True
    now = float(time.time())
    cooldown = max(0, int(cooldown_seconds or 0))
    allowed = True

    def _m(st: dict[str, Any]) -> None:
        nonlocal allowed
        raw = st.get("notify_dedupe")
        dedupe = dict(raw) if isinstance(raw, dict) else {}

        # prune old entries to keep state compact
        if dedupe:
            cutoff = now - max(300.0, float(cooldown) * 2.0)
            for dk in list(dedupe.keys()):
                try:
                    ts = float(dedupe.get(dk) or 0.0)
                except Exception:
                    ts = 0.0
                if ts <= cutoff:
                    dedupe.pop(dk, None)

        last = dedupe.get(k)
        try:
            last_ts = float(last)
        except Exception:
            last_ts = 0.0

        if cooldown > 0 and last_ts > 0 and (now - last_ts) < float(cooldown):
            allowed = False
            st["notify_dedupe"] = dedupe
            return

        dedupe[k] = now
        st["notify_dedupe"] = dedupe
        allowed = True

    _update_state(cfg, _m)
    return bool(allowed)


def _configured_notify_chat_id(cfg: BotConfig) -> int | None:
    if cfg.notify_chat_id is not None:
        return cfg.notify_chat_id
    state = _read_json(cfg.state_file)
    try:
        raw = state.get("notify_chat_id")
        if raw is None:
            return None
        return int(raw)
    except Exception:
        return None


def _proactive_health_alerts_enabled() -> bool:
    raw = os.environ.get("BOT_PROACTIVE_HEALTH_ALERTS_ENABLED", "1")
    return str(raw or "").strip().lower() in ("1", "true", "yes", "on")


def _proactive_health_alert_cooldown_seconds() -> int:
    try:
        value = int(os.environ.get("BOT_PROACTIVE_HEALTH_ALERT_COOLDOWN_SECONDS", "1800"))
    except Exception:
        value = 1800
    return max(60, min(24 * 3600, int(value)))


def _proactive_health_report_stale_seconds() -> int:
    try:
        value = int(os.environ.get("BOT_PROACTIVE_HEALTH_REPORT_STALE_SECONDS", "900"))
    except Exception:
        value = 900
    return max(300, min(24 * 3600, int(value)))


def _proactive_health_signal(cfg: "BotConfig", *, now: float) -> dict[str, Any]:
    report_path = cfg.artifacts_root / "proactive_health" / "latest.json"
    signal: dict[str, Any] = {
        "report_path": str(report_path),
        "report_found": False,
        "report_age_s": None,
        "stale_report": True,
        "status": "CRITICAL",
        "operational_status": "CRITICAL",
        "trend_status": "OK",
        "anomalies": [{"type": "missing_report"}],
        "trend_flags": [],
        "orders": [],
        "autonomy_funnel": {},
        "signature": "missing_report",
        "alert_level": "CRITICAL",
        "alert_active": True,
        "summary_reason": "missing_report",
    }
    if not report_path.exists():
        return signal

    raw = _read_json(report_path)
    report = dict(raw) if isinstance(raw, dict) else {}
    try:
        report_ts = float(report.get("ts") or 0.0)
    except Exception:
        report_ts = 0.0
    report_age_s = max(0, int(now - report_ts)) if report_ts > 0 else None
    stale_after_s = _proactive_health_report_stale_seconds()
    stale_report = bool(report_age_s is None or report_age_s >= stale_after_s)
    operational_status = str(report.get("operational_status") or report.get("status") or "OK").strip().upper() or "OK"
    trend_status = str(report.get("trend_status") or "OK").strip().upper() or "OK"
    anomalies_raw = report.get("anomalies")
    anomalies = list(anomalies_raw) if isinstance(anomalies_raw, list) else []
    trend_flags_raw = report.get("trend_flags")
    trend_flags = list(trend_flags_raw) if isinstance(trend_flags_raw, list) else []
    orders_raw = report.get("orders")
    orders = list(orders_raw) if isinstance(orders_raw, list) else []
    funnel_raw = report.get("autonomy_funnel")
    autonomy_funnel = dict(funnel_raw) if isinstance(funnel_raw, dict) else {}

    if stale_report:
        alert_level = "CRITICAL"
        summary_reason = "stale_report"
    elif operational_status in ("CRITICAL", "WARN") and anomalies:
        alert_level = operational_status
        summary_reason = ",".join(
            sorted({str(item.get("type") or "unknown") for item in anomalies if isinstance(item, dict)})
        ) or operational_status.lower()
    else:
        alert_level = "OK"
        summary_reason = "healthy"

    signature_payload = {
        "reason": summary_reason,
        "operational_status": operational_status,
        "anomalies": [
            {
                "type": str(item.get("type") or "unknown"),
                "order_id": str(item.get("order_id") or ""),
            }
            for item in anomalies
            if isinstance(item, dict)
        ],
    }
    try:
        signature = json.dumps(signature_payload, ensure_ascii=False, sort_keys=True, separators=(",", ":"))
    except Exception:
        signature = summary_reason

    return {
        "report_path": str(report_path),
        "report_found": True,
        "report_age_s": report_age_s,
        "stale_report": stale_report,
        "status": str(report.get("status") or operational_status).strip().upper() or operational_status,
        "operational_status": operational_status,
        "trend_status": trend_status,
        "anomalies": anomalies,
        "trend_flags": trend_flags,
        "orders": orders,
        "autonomy_funnel": autonomy_funnel,
        "signature": signature,
        "alert_level": alert_level,
        "alert_active": alert_level in ("WARN", "CRITICAL"),
        "summary_reason": summary_reason,
    }


def _proactive_health_alert_text(signal: dict[str, Any]) -> str:
    level = str(signal.get("alert_level") or "CRITICAL").upper()
    lines = [
        f"PonceBot proactive health alert: {level}",
    ]
    if bool(signal.get("stale_report")):
        lines.append("Reason: health report is missing or stale.")
    else:
        lines.append(f"Reason: {str(signal.get('summary_reason') or '').strip() or 'operational anomaly'}")
    report_age_s = signal.get("report_age_s")
    if report_age_s is not None:
        lines.append(f"Report age: {int(report_age_s)}s")
    lines.append(f"Operational status: {signal.get('operational_status')}")
    lines.append(f"Trend status: {signal.get('trend_status')}")
    funnel = signal.get("autonomy_funnel") if isinstance(signal.get("autonomy_funnel"), dict) else {}
    if funnel:
        lines.append(
            "Funnel: "
            f"started={int(funnel.get('slices_started', 0) or 0)} "
            f"validated={int(funnel.get('slices_validated', 0) or 0)} "
            f"closed={int(funnel.get('slices_closed', 0) or 0)} "
            f"fail_rate={float(funnel.get('implementer_fail_rate', 0.0) or 0.0):.2%}"
        )

    anomalies = [item for item in (signal.get("anomalies") or []) if isinstance(item, dict)]
    if anomalies:
        lines.append("Anomalies:")
        for item in anomalies[:4]:
            order_id = str(item.get("order_id") or "").strip()
            details = [str(item.get("type") or "unknown")]
            if order_id:
                details.append(order_id[:8])
            if item.get("open_jobs") is not None:
                details.append(f"open={item.get('open_jobs')}")
            if item.get("phase"):
                details.append(f"phase={item.get('phase')}")
            lines.append(f"- {' '.join(details)}")

    orders = [item for item in (signal.get("orders") or []) if isinstance(item, dict)]
    if orders:
        lines.append("Orders:")
        for item in orders[:3]:
            funnel = item.get("autonomy_funnel") if isinstance(item.get("autonomy_funnel"), dict) else {}
            lines.append(
                "- "
                f"{str(item.get('order_id') or '')[:8]} "
                f"phase={item.get('phase')} "
                f"mode={item.get('mode')} "
                f"open={item.get('open_jobs')} "
                f"gate={item.get('quality_gate_status') or funnel.get('quality_gate_status') or 'planned'} "
                f"quality={item.get('meaningful_improvement_seen')} "
                f"closed={int(funnel.get('slices_closed', 0) or 0)}"
            )

    trend_flags = [item for item in (signal.get("trend_flags") or []) if isinstance(item, dict)]
    if trend_flags:
        trend_bits = [f"{str(item.get('type') or 'flag')}={item.get('count')}" for item in trend_flags[:4]]
        lines.append("Trend flags: " + ", ".join(trend_bits))
    return "\n".join(lines)


def _proactive_health_recovery_text(signal: dict[str, Any]) -> str:
    lines = [
        "PonceBot proactive health recovered to OK.",
        f"Operational status: {signal.get('operational_status')}",
        f"Trend status: {signal.get('trend_status')}",
    ]
    funnel = signal.get("autonomy_funnel") if isinstance(signal.get("autonomy_funnel"), dict) else {}
    if funnel:
        lines.append(
            "Funnel: "
            f"started={int(funnel.get('slices_started', 0) or 0)} "
            f"validated={int(funnel.get('slices_validated', 0) or 0)} "
            f"closed={int(funnel.get('slices_closed', 0) or 0)} "
            f"fail_rate={float(funnel.get('implementer_fail_rate', 0.0) or 0.0):.2%}"
        )
    orders = [item for item in (signal.get("orders") or []) if isinstance(item, dict)]
    if orders:
        lines.append("Orders:")
        for item in orders[:3]:
            funnel = item.get("autonomy_funnel") if isinstance(item.get("autonomy_funnel"), dict) else {}
            lines.append(
                "- "
                f"{str(item.get('order_id') or '')[:8]} "
                f"phase={item.get('phase')} "
                f"mode={item.get('mode')} "
                f"open={item.get('open_jobs')} "
                f"gate={item.get('quality_gate_status') or funnel.get('quality_gate_status') or 'planned'} "
                f"quality={item.get('meaningful_improvement_seen')} "
                f"closed={int(funnel.get('slices_closed', 0) or 0)}"
            )
    trend_flags = [item for item in (signal.get("trend_flags") or []) if isinstance(item, dict)]
    if trend_flags:
        trend_bits = [f"{str(item.get('type') or 'flag')}={item.get('count')}" for item in trend_flags[:4]]
        lines.append("Trend flags remain: " + ", ".join(trend_bits))
    return "\n".join(lines)


def _proactive_health_notify_tick(
    *,
    cfg: "BotConfig",
    api: TelegramAPI,
    notify_chat_id: int,
    now: float,
) -> None:
    if not _proactive_health_alerts_enabled():
        return

    signal = _proactive_health_signal(cfg, now=float(now))
    state = _get_state(cfg)
    rec_raw = state.get("proactive_health_notify")
    rec = dict(rec_raw) if isinstance(rec_raw, dict) else {}
    prev_active = bool(rec.get("active", False))
    prev_signature = str(rec.get("signature") or "").strip()
    prev_level = str(rec.get("level") or "").strip().upper()
    try:
        prev_sent_at = float(rec.get("last_sent_at") or 0.0)
    except Exception:
        prev_sent_at = 0.0
    cooldown_s = float(_proactive_health_alert_cooldown_seconds())

    next_rec = {
        "active": bool(signal.get("alert_active")),
        "signature": str(signal.get("signature") or ""),
        "level": str(signal.get("alert_level") or "OK").upper(),
        "last_seen_at": float(now),
        "last_report_age_s": signal.get("report_age_s"),
        "summary_reason": str(signal.get("summary_reason") or ""),
        "report_path": str(signal.get("report_path") or ""),
        "last_sent_at": prev_sent_at,
    }

    text: str | None = None
    if bool(signal.get("alert_active")):
        changed = (not prev_active) or prev_signature != next_rec["signature"] or prev_level != next_rec["level"]
        reminder_due = (
            next_rec["level"] == "CRITICAL"
            and prev_active
            and prev_signature == next_rec["signature"]
            and prev_level == next_rec["level"]
            and prev_sent_at > 0
            and (float(now) - prev_sent_at) >= cooldown_s
        )
        if changed or reminder_due:
            text = _proactive_health_alert_text(signal)
            next_rec["last_sent_at"] = float(now)
    elif prev_active:
        text = _proactive_health_recovery_text(signal)
        next_rec["last_sent_at"] = float(now)

    if text:
        api.send_message(int(notify_chat_id), text)

    def _m(st: dict[str, Any]) -> None:
        st["proactive_health_notify"] = next_rec

    _update_state(cfg, _m)


def _migrate_state_schema(cfg: BotConfig) -> None:
    """Best-effort backward-compatible migration for mutable bot state."""
    def _m(st: dict[str, Any]) -> None:
        cur = st.get("schema_version")
        try:
            version = int(cur) if cur is not None else 1
        except Exception:
            version = 1
        if version < 2:
            # Ensure expected container types exist or are cleaned up safely.
            for key in ("threads", "watch_by_chat", "access_mode_by_chat", "model_overrides_by_chat", "effort_overrides_by_chat"):
                if key in st and not isinstance(st.get(key), dict):
                    st.pop(key, None)
            if "auth" in st and not isinstance(st.get("auth"), dict):
                st["auth"] = {}
            if "voice" in st and not isinstance(st.get("voice"), dict):
                st["voice"] = {}
            st["schema_version"] = 2

    _update_state(cfg, _m)


def main() -> None:
    logging.basicConfig(
        level=os.environ.get("LOG_LEVEL", "INFO").upper(),
        format="%(asctime)s %(levelname)s %(name)s: %(message)s",
    )

    cfg = _load_config()
    try:
        _migrate_state_schema(cfg)
    except Exception:
        LOG.exception("State migration failed; continuing with existing state")
    for issue in _sync_github_pat_git_credentials():
        LOG.warning("GIT AUTH: %s", issue)

    if cfg.codex_dangerous_bypass_sandbox and cfg.breakglass_start_reason:
        try:
            _activate_breakglass(
                cfg,
                reason=cfg.breakglass_start_reason,
                ttl_seconds=int(cfg.breakglass_ttl_seconds),
                chat_id=0,
                user_id=None,
                source="startup_env",
            )
        except Exception:
            LOG.exception("Failed to initialize startup breakglass")

    for issue in _security_startup_findings(cfg):
        LOG.warning("SECURITY CHECK: %s", issue)

    api = TelegramAPI(
        cfg.telegram_token,
        http_timeout_seconds=cfg.http_timeout_seconds,
        http_max_retries=cfg.http_max_retries,
        http_retry_initial_seconds=cfg.http_retry_initial_seconds,
        http_retry_max_seconds=cfg.http_retry_max_seconds,
        parse_mode=cfg.telegram_parse_mode,
    )
    orchestrator_queue: OrchestratorQueue | None = None
    orchestrator_profiles: dict[str, dict[str, Any]] | None = None
    orchestrator_scheduler: OrchestratorScheduler | None = None
    runbooks_scheduler: OrchestratorScheduler | None = None
    jobs: "queue.Queue[Job]" = queue.Queue(maxsize=cfg.queue_maxsize)
    stop_event = threading.Event()
    tracker = JobTracker()
    thread_mgr = ThreadManager()

    if cfg.orchestrator_enabled:
        try:
            orchestrator_profiles = load_agent_profiles(cfg.orchestrator_agent_profiles)
            # Render small placeholders for prompts (e.g. {CEO_NAME}).
            try:
                orchestrator_profiles = _render_placeholders_obj(orchestrator_profiles, ceo_name=cfg.ceo_name)
            except Exception:
                pass
            orch_storage = SQLiteTaskStorage(cfg.orchestrator_db_path)
            orchestrator_queue = OrchestratorQueue(storage=orch_storage, role_profiles=orchestrator_profiles)
            recovered = orchestrator_queue.recover_stale_running()
            if recovered:
                LOG.info("Recovered %d stale orchestrator jobs to queued state.", recovered)
            try:
                _factory_sync_repo_registry(cfg=cfg, orch_q=orchestrator_queue, now=time.time(), force=True)
            except Exception:
                LOG.exception("Factory repo registry bootstrap failed")
        except Exception:
            LOG.exception("Failed to initialize orchestrator storage/queue; disabling orchestrator for this session.")
            orchestrator_queue = None

    if orchestrator_queue is not None:
        # Optional localhost status API (snapshot + SSE stream). Disabled by default.
        if os.environ.get("BOT_STATUS_HTTP_ENABLED", "0").strip().lower() in ("1", "true", "yes", "on"):
            listen = os.environ.get("BOT_STATUS_HTTP_LISTEN", "127.0.0.1:8090").strip() or "127.0.0.1:8090"
            host = "127.0.0.1"
            port = 8090
            if ":" in listen:
                h, p = listen.rsplit(":", 1)
                if h.strip():
                    host = h.strip()
                try:
                    port = int(p.strip())
                except Exception:
                    port = 8090
            else:
                try:
                    port = int(listen)
                except Exception:
                    port = 8090
            try:
                ttl_s = int(os.environ.get("BOT_STATUS_CACHE_TTL_SECONDS", "2"))
            except Exception:
                ttl_s = 2
            try:
                interval_s = float(os.environ.get("BOT_STATUS_STREAM_INTERVAL_SECONDS", "1.0"))
            except Exception:
                interval_s = 1.0

            try:
                svc = StatusService(
                    orch_q=orchestrator_queue,
                    role_profiles=orchestrator_profiles,
                    cache_ttl_seconds=ttl_s,
                    factory_snapshot_fn=(lambda snapshot_chat_id: _factory_status_snapshot(cfg=cfg, orch_q=orchestrator_queue, chat_id=snapshot_chat_id)),
                )
                auth_token = os.environ.get("BOT_STATUS_HTTP_TOKEN", "").strip()
                allowed_origins = _parse_allowed_origins_env(os.environ.get("BOT_STATUS_HTTP_ALLOWED_ORIGINS", ""))
                if not auth_token:
                    raise RuntimeError("BOT_STATUS_HTTP_TOKEN is required when BOT_STATUS_HTTP_ENABLED=1")
                try:
                    snap_rps = float(os.environ.get("BOT_STATUS_HTTP_SNAPSHOT_RPS", "2.0"))
                except Exception:
                    snap_rps = 2.0
                try:
                    snap_burst = float(os.environ.get("BOT_STATUS_HTTP_SNAPSHOT_BURST", "4.0"))
                except Exception:
                    snap_burst = 4.0
                try:
                    max_sse = int(os.environ.get("BOT_STATUS_HTTP_MAX_SSE_PER_IP", "2"))
                except Exception:
                    max_sse = 2
                legacy_auth = os.environ.get("BOT_STATUS_HTTP_LEGACY_AUTH", "0").strip().lower() in ("1", "true", "yes", "on")
                http_srv = start_status_http_server(
                    host=host,
                    port=port,
                    status_service=svc,
                    stream_interval_s=interval_s,
                    auth_token=auth_token,
                    allowed_origins=allowed_origins,
                    allow_query_token=legacy_auth,
                    snapshot_rate_per_s=snap_rps,
                    snapshot_burst=snap_burst,
                    max_sse_per_ip=max_sse,
                )
                th = threading.Thread(target=http_srv.serve_forever, daemon=True, name="status-http")
                th.start()
                LOG.info("Status HTTP API enabled on http://%s:%s (snapshot=/api/status/snapshot stream=/api/status/stream)", host, port)
            except Exception:
                LOG.exception("Failed to start status HTTP server")

        for i in range(max(1, cfg.orchestrator_worker_count)):
            t = threading.Thread(
                target=orchestrator_worker_loop,
                kwargs={
                    "cfg": cfg,
                    "api": api,
                    "orch_q": orchestrator_queue,
                    "stop_event": stop_event,
                    "profiles": orchestrator_profiles,
                },
                daemon=True,
                name=f"orch-worker-{i+1}",
            )
            t.start()

        if cfg.orchestrator_daily_digest_seconds >= 60 and _configured_notify_chat_id(cfg):
            notify_chat_id = _configured_notify_chat_id(cfg)


            def _send_orchestrator_digest() -> None:
                if orchestrator_queue is None or notify_chat_id is None:
                    return
                try:
                    if _has_active_ceo_orders(orch_q=orchestrator_queue, chat_id=int(notify_chat_id)):
                        return
                except Exception:
                    pass
                try:
                    api.send_message(notify_chat_id, _orchestrator_daily_digest_text(orchestrator_queue))
                except Exception:
                    LOG.exception("Failed to send scheduled orchestrator digest")

            orchestrator_scheduler = OrchestratorScheduler(interval_seconds=cfg.orchestrator_daily_digest_seconds, enabled=True)
            orchestrator_scheduler.add_tick(_send_orchestrator_digest)
            orchestrator_scheduler.start()

        if _configured_notify_chat_id(cfg):
            proactive_health_chat_id = _configured_notify_chat_id(cfg)

            def _send_proactive_health_alerts() -> None:
                if proactive_health_chat_id is None:
                    return
                try:
                    _proactive_health_notify_tick(
                        cfg=cfg,
                        api=api,
                        notify_chat_id=int(proactive_health_chat_id),
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Failed to send proactive health alerts")

            proactive_health_scheduler = OrchestratorScheduler(interval_seconds=60, enabled=True)
            proactive_health_scheduler.add_tick(_send_proactive_health_alerts)
            proactive_health_scheduler.start(name="proactive-health-alerts")

        # Runbooks scheduler: enqueues autonomous tasks periodically to the notify chat.
        if cfg.runbooks_enabled:
            notify_chat_id = _configured_notify_chat_id(cfg)

            def _tick_runbooks() -> None:
                if orchestrator_queue is None:
                    return

                # /watch updates (every scheduler tick). Independent of runbooks and notify chat.
                try:
                    _tick_watch_messages(cfg=cfg, api=api, orch_q=orchestrator_queue)
                except Exception:
                    pass

                try:
                    _collapse_redundant_orders_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Redundant orders collapse tick failed")
                try:
                    _collapse_duplicate_proactive_repo_orders_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Duplicate proactive repo collapse tick failed")
                try:
                    _drain_backlog_tick(
                        orch_q=orchestrator_queue,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Backlog drain tick failed")
                try:
                    _blocked_pressure_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        profiles=orchestrator_profiles,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Blocked pressure tick failed")
                try:
                    _stalled_replan_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        profiles=orchestrator_profiles,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Stalled replan tick failed")
                try:
                    _sla_overdue_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        profiles=orchestrator_profiles,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("SLA overdue tick failed")
                try:
                    _cleanup_stale_blocked_jobs(orch_q=orchestrator_queue, now=time.time())
                except Exception:
                    LOG.exception("Hygiene stale cleanup tick failed")
                try:
                    _cleanup_proactive_local_waiting_jobs(
                        orch_q=orchestrator_queue,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Proactive local cleanup tick failed")
                try:
                    _running_watchdog_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        profiles=orchestrator_profiles,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Running watchdog tick failed")
                try:
                    _jarvis_final_sweep_tick(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        profiles=orchestrator_profiles,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Jarvis final sweep tick failed")
                try:
                    now_tick = time.time()
                    repos_now = _factory_sync_repo_registry(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        now=now_tick,
                        force=False,
                    )
                    _factory_touch_runtime_agents(
                        cfg=cfg,
                        orch_q=orchestrator_queue,
                        chat_id=(int(notify_chat_id) if notify_chat_id is not None else None),
                        now=now_tick,
                        repos=repos_now,
                    )
                except Exception:
                    LOG.exception("Factory heartbeat tick failed")
                try:
                    _cancel_non_local_children_for_skynet_factory_orders_tick(
                        orch_q=orchestrator_queue,
                        now=time.time(),
                        chat_id=(int(notify_chat_id) if notify_chat_id is not None else None),
                    )
                except Exception:
                    LOG.exception("Skynet local-only scrub tick failed")
                try:
                    _factory_ceo_strategy_timeout_tick(
                        cfg=cfg,
                        api=api,
                        orch_q=orchestrator_queue,
                        profiles=orchestrator_profiles,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Factory CEO strategy timeout tick failed")
                try:
                    _auto_merge_ready_orders_tick(
                        cfg=cfg,
                        api=api,
                        orch_q=orchestrator_queue,
                        now=time.time(),
                    )
                except Exception:
                    LOG.exception("Auto-merge ready-orders tick failed")

                if notify_chat_id is not None:
                    try:
                        _proactive_lane_tick(
                            cfg=cfg,
                            orch_q=orchestrator_queue,
                            profiles=orchestrator_profiles,
                            chat_id=int(notify_chat_id),
                            now=time.time(),
                        )
                    except Exception:
                        LOG.exception("Proactive lane tick failed")
                    try:
                        _active_order_watchdog_tick(
                            cfg=cfg,
                            orch_q=orchestrator_queue,
                            profiles=orchestrator_profiles,
                            chat_id=int(notify_chat_id),
                            now=time.time(),
                        )
                    except Exception:
                        LOG.exception("Active-order watchdog tick failed")
                    try:
                        _operational_maturity_sweep_tick(
                            cfg=cfg,
                            orch_q=orchestrator_queue,
                            now=time.time(),
                        )
                    except Exception:
                        LOG.exception("Operational maturity sweep tick failed")

                if notify_chat_id is None:
                    return
                if orchestrator_queue.is_paused_globally():
                    return
                try:
                    rbs = load_runbooks(cfg.runbooks_path)
                except Exception:
                    LOG.exception("Failed to load runbooks: %s", cfg.runbooks_path)
                    return
                if not rbs:
                    return
                # Render placeholders for runbook prompts (e.g. {CEO_NAME}).
                try:
                    rbs = [
                        Runbook(
                            runbook_id=rb.runbook_id,
                            role=rb.role,
                            interval_seconds=rb.interval_seconds,
                            prompt=_render_placeholders_text(rb.prompt, ceo_name=cfg.ceo_name),

                            mode_hint=rb.mode_hint,
                            priority=rb.priority,
                            enabled=rb.enabled,
                        )
                        for rb in rbs
                    ]
                except Exception:
                    pass
                now = time.time()
                has_active_ceo_order = False
                try:
                    has_active_ceo_order = _has_active_ceo_orders(orch_q=orchestrator_queue, chat_id=int(notify_chat_id))
                except Exception:
                    has_active_ceo_order = False
                for rb in rbs:
                    try:
                        last = orchestrator_queue.get_runbook_last_run(runbook_id=rb.runbook_id)
                        if not runbook_due(rb, last_run_at=last, now=now):
                            continue
                        if has_active_ceo_order and rb.runbook_id == "jarvis_digest":
                            continue
                        # Autopilot is implemented in-process so it can read persisted orders and current queue state.
                        if rb.runbook_id == "jarvis_autopilot":
                            try:
                                _autopilot_tick(
                                    cfg=cfg,
                                    orch_q=orchestrator_queue,
                                    profiles=orchestrator_profiles,
                                    chat_id=int(notify_chat_id),
                                    now=now,
                                )
                            except Exception:
                                LOG.exception("Autopilot tick failed")
                            orchestrator_queue.set_runbook_last_run(runbook_id=rb.runbook_id, ts=now)
                            continue
                        t = runbook_to_task(rb, chat_id=int(notify_chat_id))
                        # Apply role profile defaults so autonomous tasks behave like the same "agents".
                        try:
                            rb_role = _coerce_orchestrator_role(t.role)
                            rb_profile = _orchestrator_profile(orchestrator_profiles, rb_role)
                            rb_model = _orchestrator_model_for_profile(cfg, rb_profile)
                            rb_effort = _orchestrator_effort_for_profile(rb_profile, cfg)
                            rb_requires_approval = bool(rb_profile.get("approval_required", False)) or (t.mode_hint == "full")
                            if _effective_bypass_sandbox(cfg, chat_id=int(notify_chat_id)):
                                rb_requires_approval = False
                            rb_trace = dict(t.trace)
                            rb_trace["profile_name"] = str(rb_profile.get("name") or rb_role)
                            rb_trace["profile_role"] = rb_role
                            rb_trace["max_runtime_seconds"] = int(rb_profile.get("max_runtime_seconds") or 0)
                            t = t.with_updates(
                                role=rb_role,
                                model=rb_model,
                                effort=rb_effort,
                                requires_approval=rb_requires_approval,
                                trace=rb_trace,
                            )
                        except Exception:
                            pass
                        if not (t.artifacts_dir or "").strip():
                            t = t.with_updates(artifacts_dir=str((cfg.artifacts_root / t.job_id).resolve()))
                        orchestrator_queue.submit_task(t)
                        orchestrator_queue.set_runbook_last_run(runbook_id=rb.runbook_id, ts=now)
                    except Exception:
                        LOG.exception("Failed to enqueue runbook=%s", rb.runbook_id)

            runbooks_scheduler = OrchestratorScheduler(interval_seconds=60, enabled=True)
            runbooks_scheduler.add_tick(_tick_runbooks)
            runbooks_scheduler.start(name="orchestrator-runbooks")
    try:
        for chat_id_str, tid in _get_threads_state(cfg).items():
            try:
                cid = int(chat_id_str)
            except Exception:
                continue
            thread_mgr.set(cid, tid)
    except Exception:
        LOG.exception("Failed to load persisted threads from state file")

    if cfg.auth_enabled:
        # Security: if the bot restarts (deploy, crash, manual restart), require /login again.
        # This matches the "session lasts 12h of inactivity" model but does not persist across restarts.
        try:
            _auth_clear_all_sessions(cfg)
        except Exception:
            LOG.exception("Failed to clear auth sessions on startup")

    LOG.info(
        "Starting codexbot. workdir=%s default_mode=%s provider=%s allowed_chat_ids=%s allowed_user_ids=%s",
        cfg.codex_workdir,
        cfg.codex_default_mode,
        cfg.codex_local_provider if cfg.codex_use_oss else "default",
        sorted(cfg.allowed_chat_ids),
        sorted(cfg.allowed_user_ids),
    )

    command_suggestions_synced = False
    try:
        _sync_telegram_command_suggestions(api, cfg)
        command_suggestions_synced = True
        LOG.info("Telegram command suggestions synced.")
    except Exception:
        LOG.exception("Failed to set Telegram command suggestions at startup; will retry in poll loop")

    for i in range(cfg.worker_count):
        t = threading.Thread(
            target=worker_loop,
            kwargs={"cfg": cfg, "api": api, "jobs": jobs, "tracker": tracker, "stop_event": stop_event, "thread_mgr": thread_mgr},
            daemon=True,
            name=f"worker-{i+1}",
        )
        t.start()

    if cfg.notify_on_start:
        target = _configured_notify_chat_id(cfg)
        if target:
            try:
                api.send_message(int(target), "Poncebot is online.")
                LOG.info("Startup notification sent to chat_id=%s", int(target))
            except Exception:
                LOG.exception("Failed to send startup notification")

    try:
        start_offset = _drain_pending_updates(cfg, api) if cfg.drain_updates_on_start else 0
        poll_loop(
            cfg=cfg,
            api=api,
            jobs=jobs,
            tracker=tracker,
            stop_event=stop_event,
            thread_mgr=thread_mgr,
            orchestrator_queue=orchestrator_queue,
            orchestrator_profiles=orchestrator_profiles,
            offset=start_offset,
            command_suggestions_synced=command_suggestions_synced,
        )
    except KeyboardInterrupt:
        LOG.info("Stopping (KeyboardInterrupt)")
    finally:
        stop_event.set()
        if orchestrator_scheduler is not None:
            orchestrator_scheduler.stop()
        if runbooks_scheduler is not None:
            runbooks_scheduler.stop()


if __name__ == "__main__":
    main()
